import java.io.*;
import java.util.*;
import java.lang.*;

public class Main {
    public static class FastReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curchar;
        private int numChars;
        private SpaceCharFilter filter;

        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        public int read() {
            if (numChars == -1)
                throw new InputMismatchException();
            if (curchar >= numChars) {
                curchar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0)
                    return -1;
            }
            return buf[curchar++];
        }

        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine();
            } catch (IOException e) {
                e.printStackTrace();
            }
            return str;
        }

        public int nextInt() {
            int c = read();
            while (isspaceChar(c))
                c = read();

            int sign = 1;
            if (c == '-')
                sign = -1;
            c = read();

            int res = 0;
